import { useState } from "react"
import { BrowserRouter as Router, Route, Link, Routes, useNavigate, Navigate  } from "react-router-dom";

//Import the pages

import Page1 from "./Components/page1"
import Page2 from "./Components/page2"
import Page3 from "./Components/page3"

const About = () => {
  return (
    <>
      <h2>About</h2>
    </>
  );
};

function App() {
  return (
    <div className="App">
      <Router>
        <div className="list">
          <ul>
            <li><Link to="/">Home</Link></li>
            <li><Link to="page1">Page 1</Link></li>
            <li><Link to="page2">Page 2</Link></li>
            <li><Link to="page3">Page 3</Link></li>
          </ul>
        </div>
        <Routes>
          <Route exact path="/" element={<h1>Home Page</h1>} />
          <Route exact path="logIn" element={<h2>Ingresar</h2>} />
          <Route exact path="register" element={<h2>Register</h2>} />
          <Route exact path="page1" element={<Page1 />} />
          <Route exact path="page2" element={
            shouldRedirect ? (
              <Navigate replace to="/home" />
            ) : (
              <About />
            )
          } />
          <Route exact path="page3" element={<Page3 />} />
        </Routes>
      </Router>
    </div>
  );
}

export default App;
